'use strict';

// Baked title-block backgrounds as data-URLs (2026-06-12).
//
// GENERATED FILE — do not hand-edit the base64 blobs. Regenerate after
// re-baking any titleblock-templates/*.png (pdftoppm on the (blank).pdf
// templates) with:
//   base64 -i titleblock-templates/<name>.png | tr -d '\n'
// and splice the output into the matching constant below.
//
// Why data-URLs instead of the PNG files on disk: when the app runs from
// file://, an <img> loaded from a relative path TAINTS any canvas it is
// drawn into — getImageData (the white→transparent keying in
// 87-titleblock.js) and toDataURL (the vector-PDF export shim's image
// embed in 44-pdf-export.js) both throw SecurityError, so the title block
// silently vanished from exported PDFs. A data-URL image never taints.
// 87-titleblock.js prefers these constants when present and falls back to
// the file paths if this script is missing.

const TB_RIGHT_BG_B64 = 'data:image/png;base64,';
const TB_BOTTOM_BG_B64 = 'data:image/png;base64,';
const TB_SKETCH_BG_B64 = 'data:image/png;base64,';
